puts "================================"
puts "   Analyseur de journalistes    "
puts "================================"
puts "1 - Nombre de handles"
puts "2 - Handle le plus court"
puts "3 - Handles de 5 caracteres"
puts "4 - Handles avec majuscule"
puts "5 - Tri alphabetique"
puts "6 - Tri par taille"
