puts ""

if choix == "1"
  puts "Il y a #{journalists.length} handles."

elsif choix == "2"
  shortest = journalists.min_by { |h| h[1..-1].length }
  puts "Le handle le plus court est #{shortest}."

elsif choix == "3"
  count = journalists.count { |h| h[1..-1].length == 5 }
  puts "Il y a #{count} handles de 5 caracteres."

elsif choix == "4"
  count = journalists.count { |h| h[1] =~ /[A-Z]/ }
  puts "Il y a #{count} handles qui commencent par une majuscule."

elsif choix == "5"
  puts "Handles par ordre alphabetique :"
  journalists.sort.each { |h| puts h }

elsif choix == "6"
  puts "Handles tries par taille :"
  journalists.sort_by { |h| h[1..-1].length }.each { |h| puts h }

elsif choix == "7"
  position = journalists.index("@epenser")
  puts "@epenser est en position #{position}."

elsif choix == "8"
  distribution = Hash.new(0)
  journalists.each { |h| distribution[h[1..-1].length] += 1 }
  puts "Repartition par taille :"
  distribution.sort.each { |taille, nombre| puts "  #{taille} caracteres : #{nombre} handles" }

